  "verses": [
    {
      "n": 1,
      "column": "left",
      "text": "UN tas KUNGS run-\nnaja us Mohsu/ un faz-\nzija:"
    },
    {
      "n": 2,
      "column": "left",
      "text": "Runna us Aâronu/ un faz-\nki us to: Kad tu tohs Etjes-Luk-\nturus eededsinaji/ tad buhs teem\nfeptineem Etjes-Luktureein itt\nprett to Lukturu spihdeht."
    },
    {
      "n": 3,
      "column": "left",
      "text": "Un Aârons darrija ta/ tam\nLukturam pretti eededsinaja\nwiꞥſch winna Etjes-Lukturis/\nittin ka tas KUNGS Mohsum\nbija pawehlejis."
    },
    {
      "n": 4,
      "column": "left",
      "text": "Tad nu schis Luktura Tai-\nfijums bija no tihra Selta/ tik\nlab winna Kahts/ un winna\nBukkes bija zeets Darbs/ pehz\ntabs Sihnes/ ko tas KUNGS\nMohsum rahdijs bija/ ta bija\nwiꞥſch to Lukturu darrijs."
    },
    {
      "n": 5,
      "column": "left",
      "text": "Un tas KUNGS runnaja\nus Mohsu/ un fazzija:"
    },
    {
      "n": 6,
      "column": "left",
      "text": "Nemm tohs Lewitus no\nIsraëta Behrun Widdus/ un\nschêihsti tohs."
    },
    {
      "n": 7,
      "column": "left",
      "text": "Un ta buhs tew darriht\nwinnas schêihstidams/ flakki\nGrehku-Uhdeni us teem/ un teem\nbuhs weenn dsennamu Nasi likt\npahr wiꞥſa fa:wu Meefu eet/ un\nfa:wu Drehbes masgaht un\nschêihstitees."
    },
    {
      "n": 8,
      "column": "right",
      "text": "Pehz to buhs winneent\nneent weenu Wehrfeti no leeleen\nLohpeent/ ar winna Ehdamu\nUppuru/ no Kweeschu-Milteem,\nar Etji-fajaukteem/ un weeni\nzittu jaunu Wehrfi buhs ten-\nneent par Grehku-Uppuru."
    },
    {
      "n": 9,
      "column": "right",
      "text": "Un tew buhs tohs Lewitu-\npreeksch Sa-eeschanas Telt-\nwest/ un winnu Israëta Behru-\nDraudsi fapulzinaht."
    },
    {
      "n": 10,
      "column": "right",
      "text": "Un tohs Lewitus preeksch\nto KUNGU west/ un teem Isra-\netu Behrneem buhs fawas Roh-\nkas us teem Lewiteem lift."
    },
    {
      "n": 11,
      "column": "right",
      "text": "Un Aâronam buhs tohs\nLewitus pahrzillaht/ par weeni\nKustinaschanas-Uppuru/ preeksch\nto KUNGU to Israëta Behru-\nlabbad/ ka teem jakaipo ta KUN-\nGA Darbos."
    },
    {
      "n": 12,
      "column": "right",
      "text": "Un teem Lewiteem buhs\nfawas Rohkas us to Wehrschu-\nGalwn lift/ pehz to pataisi tu-\nweennu par Grehku-Uppuru/ un-\nweennu par Dedsamu-Uppuru-\ntam KUNGAM/ par teem Le-\nwiteem Salihdsinaschann darri-\ndains."
    },
    {
      "n": 13,
      "column": "right",
      "text": "Un tew buhs tohs Lewi-\ntus preeksch Aârona/ un preeksch\nwinna Dehleem west/ un tohs-\ntam KUNGAM par Kustina-\nschanas-Uppuru pahrzillaht."
    },
    {
      "n": 14,
      "column": "right",
      "text": "Un tew buhs tohs Lewitus\nno Israëta Behrun Widdus at-\nschkirt/ ka tee Lewiti manni effus."
    },
    {
      "n": 15,
      "column": "right",
      "text": "Un pehz to laid tee Lewitt\nnahk Sa-eeschanas Telti kalpo-\ndami/ un tew buhs tohs schêih-\npuht/"
    }
  ],
  "confidence": "high",
  "notes": ""
}
